#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, S;
        scanf("%d %d", &N, &S);
        int cupcakes[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &cupcakes[i]);
        }
        double totalEnergy = 0;
        double reserve = 0;
        for (int i = 0; i < N; i++) {
            double energy = cupcakes[i] + reserve;
            if (energy > S) {
                totalEnergy += energy * energy;
                reserve = 0;
            } else {
                totalEnergy += energy * energy;
                reserve = S - energy;
            }
        }
        double totalCupcakes = 0;
        for (int i = 0; i < N; i++) {
            totalCupcakes += cupcakes[i];
        }
        printf("%.5f\n", totalEnergy / totalCupcakes);
    }
    return 0;
}

