const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, S] = readline().split(' ').map(Number);
    const cupcakes = readline().split(' ').map(Number);
    let totalEnergy = 0;
    let reserve = 0;
    for (let j = 0; j < N; j++) {
        const energy = cupcakes[j] + reserve;
        if (energy > S) {
            totalEnergy += energy ** 2;
            reserve = 0;
        } else {
            totalEnergy += energy ** 2;
            reserve = S - energy;
        }
    }
    const totalCupcakes = cupcakes.reduce((a, b) => a + b, 0);
    console.log((totalEnergy / totalCupcakes).toFixed(5));
}
